/*! Minimal FileSaver fallback for this project */
(function(g){if(g.saveAs)return;g.saveAs=function(blob,name){var u=URL.createObjectURL(blob),a=document.createElement("a");a.href=u;a.download=name||"download";document.body.appendChild(a);a.click();a.remove();setTimeout(function(){URL.revokeObjectURL(u)},1000)}})(this);
